if ({
        &&& (post1_self_.valid())
        &&& (r1.valid_ack(pkt))
        &&& (SingleDelivery::receive(pre_self_@, post1_self_@, pkt@, r1.get_ack()@, r1.get_abstracted_ack_set()))
        &&& (r1 is FreshPacket ==> SingleDelivery::new_single_message(pre_self_@, pkt@))
        &&& (r1 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_self_@, pkt@))
        &&& (post2_self_.valid())
        &&& (r2.valid_ack(pkt))
        &&& (SingleDelivery::receive(pre_self_@, post2_self_@, pkt@, r2.get_ack()@, r2.get_abstracted_ack_set()))
        &&& (r2 is FreshPacket ==> SingleDelivery::new_single_message(pre_self_@, pkt@))
        &&& (r2 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_self_@, pkt@))
    }) {
        // Best-effort: prove what's provable.
        // The concrete HashMap equality cannot be derived from view-level specs because
        // (a) HashMap is external_body and has no view->concrete axiom, and
        // (b) receive_ack uses `..post` (not `..pre`), so receive_state view is
        //     unconstrained when ack_seqno > num_packets_acked.
        // We still emit the assertion so the postcondition is attempted.
        assert(det_receive_impl_equal(r1, r2, post1_self_, post2_self_));
    }
